use std::collections::HashMap;

trait DistanceMeasurable {
    fn get_normalized_vector(&self) -> Vec<f64>;
}

struct MatrixData { 
    name: String,
    values: Vec<f64>,
}

impl DistanceMeasurable for MatrixData {
    fn get_normalized_vector(&self) -> Vec<f64> {
        let sum_sq: f64 = self.values.iter().map(|&x| x * x).sum();
        if sum_sq == 0.0 {
            return vec![0.0; self.values.len()];
        }
        let norm = sum_sq.sqrt();
        self.values.iter().map(|&x| x / norm).collect()
    }
}

fn calculate_metric<T: DistanceMeasurable>(a: &T, b: &T) -> f64 {
    let vec_a = a.get_normalized_vector();
    let vec_b = b.get_normalized_vector();

    if vec_a.len() != vec_b.len() {
        panic!("Dimensional mismatch in input matrices.");
    }

    let dot_product: f64 = vec_a.iter().zip(vec_b.iter()).map(|(&x, &y)| x * y).sum();

    dot_product / (vec_a.len() as f64).sqrt()
}

fn main() {
    let dataset1 = MatrixData { name: String::from("A"), values: vec![3.0, 4.0] };
    let dataset2 = MatrixData { name: String::from("B"), values: vec![5.0, 12.0] };

    let metric_value = calculate_metric(&dataset1, &dataset2);
    println!("Computed distance metric: {}", metric_value);
}

use std::collections::HashMap;

trait Movable {
    fn check_collision(&self, map_data: &HashMap<String, bool>) -> bool;
}

struct Tank { 
    id: u32,
    owner: String,
}

struct Scout {
    id: u32,
    owner: String,
}

impl Movable for Tank {
    fn check_collision(&self, map_data: &HashMap<String, bool>) -> bool {
        map_data.get("path_key_tank").copied().unwrap_or(true)
    }
}

impl Movable for Scout {
    fn check_collision(&self, map_data: &HashMap<String, bool>) -> bool {
        map_data.get("path_key_scout").copied().unwrap_or(true)
    }
}

struct UnitRegistry {
    units: HashMap<u32, Box<dyn Movable>>, 
}

impl UnitRegistry {
    fn new() -> Self {
        UnitRegistry { units: HashMap::new() }
    }

    fn add_unit(&mut self, unit: Box<dyn Movable>, id: u32) {
        self.units.insert(id, unit);
    }

    fn can_all_move(&self, map_data: &HashMap<String, bool>) -> bool {
        for unit in self.units.values() {
            if !unit.check_collision(map_data) {
                return false;
            }
        }
        true
    }
}

fn main() {
    let mut registry = UnitRegistry::new();
    let tank1 = Box::new(Tank { id: 101, owner: String::from("PlayerA") });
    let scout1 = Box::new(Scout { id: 201, owner: String::from("PlayerB") });
    registry.add_unit(tank1, 101);
    registry.add_unit(scout1, 201);

    let mut map = HashMap::new();
    map.insert(String::from("path_key_tank"), false); 
    map.insert(String::from("path_key_scout"), true); 

    if registry.can_all_move(&map) {
        println!("All units can proceed through the current map area.");
    } else {
        println!("Movement blocked for at least one unit.");
    }
}

use std::collections::VecDeque;

#[derive(Debug, Clone, PartialEq)]
enum ConnectionState {
    Disconnected,
    Connecting(u32),
    Connected,
}

struct StateTracker {
    current_state: ConnectionState,
    event_log: VecDeque<String>,
    max_history: usize,
}

impl Default for StateTracker {
    fn default() -> Self {
        StateTracker {
            current_state: ConnectionState::Disconnected,
            event_log: VecDeque::with_capacity(10),
            max_history: 10,
        }
    }
}

trait StateMachine {
    fn transition(&mut self, next_state: ConnectionState) -> Option<String>;
}

impl StateMachine for StateTracker {
    fn transition(&mut self, next_state: ConnectionState) -> Option<String> {
        let previous_state = std::mem::replace(&mut self.current_state, next_state.clone());
        self.event_log.push_back(format!("Transitioned from {:?} to {:?}", previous_state, next_state));
        if self.event_log.len() > self.max_history {
            self.event_log.pop_front();
        }
        Some(format!("Current state updated: ?"))
    }
}

fn main() {
    let mut tracker = StateTracker::default();
    println!("Initial State: {:?}", tracker.current_state);

    if let Some(event) = tracker.transition(ConnectionState::Connecting(5)) {
        println!("Event Fired: {}", event);
    }

    if let Some(event) = tracker.transition(ConnectionState::Connected) {
        println!("Event Fired: {}", event);
    }

    println!("Final Log: {:?}", tracker.event_log);
}

use std::collections::HashMap;

trait NetworkResource {
    fn initialize(&self) -> Result<(), String>;
    fn close(&self) -> Result<(), String>;
}

struct ConnectionId(u64);
impl NetworkResource for ConnectionId {
    fn initialize(&self) -> Result<(), String> {
        println!("Initializing connection ID: {}", self.0);
        Ok(())
    }
    fn close(&self) -> Result<(), String> {
        println!("Closing connection ID: {}", self.0);
        Ok(())
    }
}

struct GatewayConfig {
    resources: HashMap<String, Box<dyn NetworkResource>>,
}
impl GatewayConfig {
    fn new() -> Self {
        GatewayConfig {
            resources: HashMap::new()
        }
    }
    fn register_resource(&mut self, name: String, resource: Box<dyn NetworkResource>) {
        self.resources.insert(name, resource);
    }
    fn startup(&self) -> Result<(), String> {
        for (name, resource) in &self.resources {
            println!("n--- Starting component: {} ---", name);
            resource.initialize()?;
        }
        Ok(())
    }
    fn shutdown(&self) -> Result<(), String> {
        let mut results = Vec::new();
        for (name, resource) in &self.resources {
            println!("n--- Shutting down component: {} ---", name);
            match resource.close() {
                Ok(_) => results.push(format!("Success: {}", name)),
                Err(e) => results.push(format!("Error on {}: {}", name, e)),
            }
        }
        println!("nShutdown summary:n{}", results.join("n"));
        Ok(())
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut config = GatewayConfig::new();
    config.register_resource("AuthService".to_string(), Box::new(ConnectionId(100)));
    config.register_resource("MetricsCollector".to_string(), Box::new(ConnectionId(200)));

    println!("--- Application Startup ---");
    config.startup()?;

    println!("n--- Application Shutdown ---");
    config.shutdown()?;
    Ok(())
}

use std::collections::hash_map::DefaultHasher;
use std::hash::{Hash, Hasher};

struct StateRecord {
    sequence_number: u64,
    key_data: Vec<u8>,
    value_data: Vec<u8>,
}

impl Hash for StateRecord {
    fn hash<H>(&self, state: &mut H) where H: Hasher {
        self.sequence_number.hash(state);
        self.key_data.hash(state);
        self.value_data.hash(state);
    }
}

impl PartialEq for StateRecord {
    fn eq(&self, other: &Self) -> bool {
        self.sequence_number == other.sequence_number &&
        self.key_data == other.key_data &&
        self.value_data == other.value_data
    }
}

impl Eq for StateRecord {}

fn calculate_hash<T: Hash>(item: &T) -> u64 {
    let mut s = DefaultHasher::new();
    item.hash(&mut s);
    s.finish()
}

fn main() {
    let record1 = StateRecord { sequence_number: 101, key_data: b"user".to_vec(), value_data: vec![1] };
    let record2 = StateRecord { sequence_number: 102, key_data: b"config".to_vec(), value_data: vec![5] };

    let hash1 = calculate_hash(&record1);
    let hash2 = calculate_hash(&record2);

    println!("Record 1 Hash: {}", hash1);
    println!("Record 2 Hash: {}", hash2);
}
